#include <iostream>
#include <string>

std::string convertToBase(int num, int k) {
    if (num == 0)
        return "0";

    std::string result = "";
    while (num > 0) {
        int remainder = num % k;
        num /= k;
        result = std::to_string(remainder) + result;
    }

    return result;
}

int main() {
    int num = 10;
    int k = 2;
    std::string result = convertToBase(num, k);
    std::cout << "The number " << num << " in base " << k << " is: " << result << std::endl;

    return 0;
}
```

